const express = require('express');
const app = express();

// API version configuration with lifecycle management
const API_VERSIONS = {
  v1: {
    status: 'deprecated',
    deprecatedDate: '2025-01-01',
    sunsetDate: '2025-06-01',
    replacementVersion: 'v3'
  },
  v2: {
    status: 'supported',
    deprecatedDate: null,
    sunsetDate: '2026-01-01',
    replacementVersion: 'v3'
  },
  v3: {
    status: 'current',
    deprecatedDate: null,
    sunsetDate: null,
    replacementVersion: null
  }
};

// Middleware to enforce version sunset policy
function apiVersionControl(req, res, next) {
  // Extract version from URL path (e.g., /api/v1/users)
  const versionMatch = req.path.match(/^\/api\/(v\d+)/);

  if (!versionMatch) {
    return res.status(400).json({
      error: 'API version not specified',
      message: 'Please use versioned endpoints: /api/v3/...'
    });
  }

  const version = versionMatch[1];
  const versionConfig = API_VERSIONS[version];

  if (!versionConfig) {
    return res.status(404).json({
      error: 'API version not found',
      supportedVersions: Object.keys(API_VERSIONS)
    });
  }

  const now = new Date();

  // Block access to sunset versions
  if (versionConfig.sunsetDate && new Date(versionConfig.sunsetDate) < now) {
    return res.status(410).json({
      error: 'API version sunset',
      message: `API ${version} was sunset on ${versionConfig.sunsetDate}`,
      replacementVersion: versionConfig.replacementVersion,
      migrationGuide: `https://docs.example.com/api/migration/${version}-to-${versionConfig.replacementVersion}`
    });
  }

  // Add deprecation warnings for deprecated versions
  if (versionConfig.status === 'deprecated') {
    const daysUntilSunset = Math.ceil(
      (new Date(versionConfig.sunsetDate) - now) / (1000 * 60 * 60 * 24)
    );

    res.set({
      'Deprecation': `version="${version}"`,
      'Sunset': versionConfig.sunsetDate,
      'Link': `<https://docs.example.com/api/${versionConfig.replacementVersion}>; rel="successor-version"`,
      'Warning': `299 - "API ${version} is deprecated and will be sunset in ${daysUntilSunset} days"`
    });

    // Log deprecation usage for monitoring
    console.warn({
      event: 'deprecated_api_usage',
      version,
      path: req.path,
      clientIp: req.ip,
      userAgent: req.headers['user-agent'],
      daysUntilSunset
    });
  }

  req.apiVersion = version;
  next();
}

// Apply middleware to all API routes
app.use('/api', apiVersionControl);

// Example route handlers
const v1Router = express.Router();
const v2Router = express.Router();
const v3Router = express.Router();

v1Router.get('/users/:id', (req, res) => {
  // Legacy endpoint - limited functionality
  res.json({ message: 'v1 endpoint - deprecated' });
});

v3Router.get('/users/:id', (req, res) => {
  // Current endpoint with all security features
  res.json({ message: 'v3 endpoint - current' });
});

app.use('/api/v1', v1Router);
app.use('/api/v2', v2Router);
app.use('/api/v3', v3Router);

// Health check endpoint for monitoring
app.get('/api/versions', (req, res) => {
  res.json({
    versions: API_VERSIONS,
    currentVersion: 'v3',
    recommendation: 'Use v3 for all new integrations'
  });
});

app.listen(3000, () => {
  console.log('API server with version control running on port 3000');
});

// ApiVersion.java - Custom annotation for version metadata
package com.example.api.versioning;

import java.lang.annotation.*;

@Target({ElementType.TYPE, ElementType.METHOD})
@Retention(RetentionPolicy.RUNTIME)
@Documented
public @interface ApiVersion {
    String value();
    VersionStatus status() default VersionStatus.SUPPORTED;
    String sunsetDate() default "";
    String replacementVersion() default "";
}

// VersionStatus.java - Enum for version lifecycle
public enum VersionStatus {
    CURRENT,
    SUPPORTED,
    DEPRECATED,
    SUNSET
}

// ApiVersionInterceptor.java - Request interceptor
package com.example.api.versioning;

import org.springframework.stereotype.Component;
import org.springframework.web.method.HandlerMethod;
import org.springframework.web.servlet.HandlerInterceptor;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.time.temporal.ChronoUnit;

@Component
public class ApiVersionInterceptor implements HandlerInterceptor {

    private static final Logger log = LoggerFactory.getLogger(ApiVersionInterceptor.class);

    @Override
    public boolean preHandle(HttpServletRequest request, 
                           HttpServletResponse response, 
                           Object handler) throws Exception {

        if (!(handler instanceof HandlerMethod)) {
            return true;
        }

        HandlerMethod handlerMethod = (HandlerMethod) handler;
        ApiVersion apiVersion = handlerMethod.getMethodAnnotation(ApiVersion.class);

        if (apiVersion == null) {
            apiVersion = handlerMethod.getBeanType().getAnnotation(ApiVersion.class);
        }

        if (apiVersion == null) {
            return true;
        }

        // Check if version is sunset
        if (apiVersion.status() == VersionStatus.SUNSET) {
            response.setStatus(HttpServletResponse.SC_GONE);
            response.setHeader("Content-Type", "application/json");
            response.setHeader("Sunset", apiVersion.sunsetDate());
            response.setHeader("Link", 
                String.format("<https://api.example.com/%s>; rel=\"successor-version\"",
                    apiVersion.replacementVersion()));

            String errorJson = String.format(
                "{\"error\":\"API version sunset\"," +
                "\"message\":\"API %s was sunset on %s\"," +
                "\"replacementVersion\":\"%s\"}",
                apiVersion.value(),
                apiVersion.sunsetDate(),
                apiVersion.replacementVersion()
            );

            response.getWriter().write(errorJson);
            return false;
        }

        // Handle deprecated versions
        if (apiVersion.status() == VersionStatus.DEPRECATED) {
            String sunsetDate = apiVersion.sunsetDate();
            if (!sunsetDate.isEmpty()) {
                LocalDate sunset = LocalDate.parse(sunsetDate, DateTimeFormatter.ISO_DATE);
                LocalDate now = LocalDate.now();

                // Auto-sunset if past sunset date
                if (now.isAfter(sunset)) {
                    response.setStatus(HttpServletResponse.SC_GONE);
                    response.setHeader("Content-Type", "application/json");
                    String errorJson = String.format(
                        "{\"error\":\"API version sunset\"," +
                        "\"message\":\"API %s was sunset on %s\"}",
                        apiVersion.value(),
                        sunsetDate
                    );
                    response.getWriter().write(errorJson);
                    return false;
                }

                // Add deprecation headers
                long daysUntilSunset = ChronoUnit.DAYS.between(now, sunset);
                response.setHeader("Deprecation", "version=\"" + apiVersion.value() + "\"");
                response.setHeader("Sunset", sunsetDate);
                response.setHeader("Link",
                    String.format("<https://api.example.com/%s>; rel=\"successor-version\"",
                        apiVersion.replacementVersion()));
                response.setHeader("Warning",
                    String.format("299 - \"API %s is deprecated and will be sunset in %d days\"",
                        apiVersion.value(), daysUntilSunset));

                // Log deprecated usage
                log.warn("Deprecated API usage: version={}, path={}, clientIp={}, daysUntilSunset={}",
                    apiVersion.value(),
                    request.getRequestURI(),
                    request.getRemoteAddr(),
                    daysUntilSunset);
            }
        }

        return true;
    }
}

// WebConfig.java - Register interceptor
package com.example.api.config;

import com.example.api.versioning.ApiVersionInterceptor;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Configuration;
import org.springframework.web.servlet.config.annotation.InterceptorRegistry;
import org.springframework.web.servlet.config.annotation.WebMvcConfigurer;

@Configuration
public class WebConfig implements WebMvcConfigurer {

    @Autowired
    private ApiVersionInterceptor apiVersionInterceptor;

    @Override
    public void addInterceptors(InterceptorRegistry registry) {
        registry.addInterceptor(apiVersionInterceptor)
                .addPathPatterns("/api/**");
    }
}

