package com.example.api.controller;

import com.example.api.versioning.ApiVersion;
import com.example.api.versioning.VersionStatus;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/v1")
@ApiVersion(
    value = "v1",
    status = VersionStatus.DEPRECATED,
    sunsetDate = "2025-06-01",
    replacementVersion = "v3"
)
public class UserControllerV1 {

    @GetMapping("/users/{id}")
    public UserResponse getUser(@PathVariable Long id) {
        // Legacy implementation
        return new UserResponse(id, "John Doe");
    }
}

@RestController
@RequestMapping("/api/v3")
@ApiVersion(value = "v3", status = VersionStatus.CURRENT)
public class UserControllerV3 {

    @GetMapping("/users/{id}")
    public UserResponse getUser(@PathVariable Long id) {
        // Current implementation with enhanced security
        return new UserResponse(id, "John Doe", true);
    }
}
